//! `#[derive(ReferenceEq)]` — shallow observational identity for the
//! MetaModelica value types generated by mmtorust.
//!
//! MMC boxes every record and its `referenceEq` is total pointer identity.
//! The Rust port unboxes non-recursive records/uniontypes, so true pointer
//! identity does not exist for them; the strongest identity an unboxed,
//! immutable value can have is *pairwise-identical fields* (each compared
//! with `ReferenceEq` again, bottoming out at pointer identity for `Arc`/
//! `Rc` handles and value identity for scalars). Two values that agree
//! under this relation are indistinguishable from "the same object" to any
//! MetaModelica code, which is exactly the property the MM reuse/cache
//! idioms (`if referenceEq(new, old) then old else new`) rely on. See
//! `try_emit_reference_eq` in mmtorust/src/codegen.rs for the concrete-type
//! lowering this derive mirrors, and `metamodelica::ReferenceEq` for the
//! base impls.
//!
//! The expansion bounds every type parameter with
//! `metamodelica::ReferenceEq` (like `derive(Clone)` bounds `Clone`); every
//! MM-representable type implements the trait, so the bound never locks a
//! type out.

use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, Data, DeriveInput, Fields, Index};

/// True if the field type is syntactically `Arc<…>` (the MMC boxed-value
/// handle). Used by [`derive_meta_cmp`] to give such fields a pointer-identity
/// fast path.
fn is_arc(ty: &syn::Type) -> bool {
    if let syn::Type::Path(tp) = ty
        && let Some(seg) = tp.path.segments.last() {
            return seg.ident == "Arc";
        }
    false
}

/// `#[derive(MetaCmp)]` — generates `PartialEq`, `PartialOrd` and `Ord` for the
/// MetaModelica value types produced by mmtorust, but with a pointer-identity
/// fast path on every `Arc<…>` field: two `Arc`s that are the *same allocation*
/// compare equal without dereferencing.
///
/// This is a faithful port of the MMC runtime `valueCompare`
/// (`SimulationRuntime/c/meta/meta_modelica.c`), which begins every (recursive)
/// comparison with `if (lhs == rhs) return 0;`. That short-circuit is what lets
/// OMC compare the *cyclic* NF data structures (`InstNode` caches a `Function`
/// whose `node` points back to the `InstNode`): a shared sub-object is caught by
/// pointer identity before the comparison can recurse into the cycle. Rust's
/// `#[derive(Ord)]`/`Arc<T>: Ord` have no such short-circuit and recurse forever
/// (stack overflow). The fast path never changes a result — identical `Arc`s
/// always hold equal values — it only terminates the cyclic descent.
#[proc_macro_derive(MetaCmp)]
pub fn derive_meta_cmp(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let name = &input.ident;

    // Per-trait generics: bound every type parameter with the trait the impl
    // requires, exactly as the builtin derives do.
    let bound = |path: proc_macro2::TokenStream| {
        let mut g = input.generics.clone();
        for p in g.type_params_mut() {
            p.bounds.push(syn::parse_quote!(#path));
        }
        g
    };
    let eq_g = bound(quote!(::core::cmp::PartialEq));
    let ord_g = bound(quote!(::core::cmp::Ord));
    let pord_g = bound(quote!(::core::cmp::Ord));
    let (eq_impl, _, eq_where) = eq_g.split_for_impl();
    let (ord_impl, _, ord_where) = ord_g.split_for_impl();
    let (pord_impl, _, pord_where) = pord_g.split_for_impl();
    let (_, ty_generics, _) = input.generics.split_for_impl();

    // `eq` field test and `cmp` field ordering for one field, given the two
    // borrowed sub-values and whether the field is an `Arc<…>`.
    let eq_one = |l: &proc_macro2::TokenStream, r: &proc_macro2::TokenStream, arc: bool| {
        if arc {
            quote! { (::std::sync::Arc::ptr_eq(#l, #r) || #l == #r) }
        } else {
            quote! { #l == #r }
        }
    };
    let cmp_one = |l: &proc_macro2::TokenStream, r: &proc_macro2::TokenStream, arc: bool| {
        if arc {
            quote! { (if ::std::sync::Arc::ptr_eq(#l, #r) { ::core::cmp::Ordering::Equal } else { ::core::cmp::Ord::cmp(#l, #r) }) }
        } else {
            quote! { ::core::cmp::Ord::cmp(#l, #r) }
        }
    };

    let (eq_body, cmp_body) = match &input.data {
        Data::Struct(data) => {
            let (eqs, cmps) = struct_field_cmps(&data.fields, &eq_one, &cmp_one);
            (
                quote! { #(#eqs)&&* },
                chain_cmps(&cmps),
            )
        }
        Data::Enum(data) => {
            let mut eq_arms = Vec::new();
            let mut cmp_arms = Vec::new();
            for v in &data.variants {
                let vname = &v.ident;
                match &v.fields {
                    Fields::Unit => {
                        eq_arms.push(quote! { (Self::#vname, Self::#vname) => true, });
                        cmp_arms.push(quote! { (Self::#vname, Self::#vname) => ::core::cmp::Ordering::Equal, });
                    }
                    Fields::Named(named) => {
                        let names: Vec<_> = named.named.iter().map(|f| f.ident.as_ref().unwrap()).collect();
                        let arcs: Vec<bool> = named.named.iter().map(|f| is_arc(&f.ty)).collect();
                        let l: Vec<_> = names.iter().map(|n| quote::format_ident!("__l_{}", n)).collect();
                        let r: Vec<_> = names.iter().map(|n| quote::format_ident!("__r_{}", n)).collect();
                        let eqs: Vec<_> = (0..names.len()).map(|i| { let (li,ri)=(&l[i],&r[i]); eq_one(&quote!(#li), &quote!(#ri), arcs[i]) }).collect();
                        let cmps: Vec<_> = (0..names.len()).map(|i| { let (li,ri)=(&l[i],&r[i]); cmp_one(&quote!(#li), &quote!(#ri), arcs[i]) }).collect();
                        let eq_all = if eqs.is_empty() { quote!(true) } else { quote!(#(#eqs)&&*) };
                        let cmp_all = chain_cmps(&cmps);
                        eq_arms.push(quote! { (Self::#vname { #(#names: #l),* }, Self::#vname { #(#names: #r),* }) => #eq_all, });
                        cmp_arms.push(quote! { (Self::#vname { #(#names: #l),* }, Self::#vname { #(#names: #r),* }) => #cmp_all, });
                    }
                    Fields::Unnamed(unnamed) => {
                        let arcs: Vec<bool> = unnamed.unnamed.iter().map(|f| is_arc(&f.ty)).collect();
                        let l: Vec<_> = (0..unnamed.unnamed.len()).map(|i| quote::format_ident!("__l{}", i)).collect();
                        let r: Vec<_> = (0..unnamed.unnamed.len()).map(|i| quote::format_ident!("__r{}", i)).collect();
                        let eqs: Vec<_> = (0..l.len()).map(|i| { let (li,ri)=(&l[i],&r[i]); eq_one(&quote!(#li), &quote!(#ri), arcs[i]) }).collect();
                        let cmps: Vec<_> = (0..l.len()).map(|i| { let (li,ri)=(&l[i],&r[i]); cmp_one(&quote!(#li), &quote!(#ri), arcs[i]) }).collect();
                        let eq_all = if eqs.is_empty() { quote!(true) } else { quote!(#(#eqs)&&*) };
                        let cmp_all = chain_cmps(&cmps);
                        eq_arms.push(quote! { (Self::#vname(#(#l),*), Self::#vname(#(#r),*)) => #eq_all, });
                        cmp_arms.push(quote! { (Self::#vname(#(#l),*), Self::#vname(#(#r),*)) => #cmp_all, });
                    }
                }
            }
            // Different variants: order by declaration index (== the
            // discriminant the builtin derive uses). `__variant_index` is a
            // local closure so the fallback arm stays simple.
            let idx_arms = data.variants.iter().enumerate().map(|(i, v)| {
                let vname = &v.ident;
                let i = i as isize;
                match &v.fields {
                    Fields::Unit => quote! { Self::#vname => #i, },
                    Fields::Named(_) => quote! { Self::#vname { .. } => #i, },
                    Fields::Unnamed(_) => quote! { Self::#vname(..) => #i, },
                }
            }).collect::<Vec<_>>();
            let idx_fn = quote! {
                let __idx = |__s: &Self| -> isize { match __s { #(#idx_arms)* } };
            };
            (
                quote! {
                    #[allow(unreachable_patterns)]
                    match (self, other) {
                        #(#eq_arms)*
                        _ => false,
                    }
                },
                quote! {
                    #idx_fn
                    #[allow(unreachable_patterns)]
                    match (self, other) {
                        #(#cmp_arms)*
                        _ => ::core::cmp::Ord::cmp(&__idx(self), &__idx(other)),
                    }
                },
            )
        }
        Data::Union(_) => {
            return syn::Error::new_spanned(name, "MetaCmp cannot be derived for unions")
                .to_compile_error()
                .into();
        }
    };

    let expanded = quote! {
        impl #eq_impl ::core::cmp::PartialEq for #name #ty_generics #eq_where {
            fn eq(&self, other: &Self) -> bool { #eq_body }
        }
        impl #ord_impl ::core::cmp::Ord for #name #ty_generics #ord_where {
            fn cmp(&self, other: &Self) -> ::core::cmp::Ordering { #cmp_body }
        }
        impl #pord_impl ::core::cmp::PartialOrd for #name #ty_generics #pord_where {
            fn partial_cmp(&self, other: &Self) -> ::core::option::Option<::core::cmp::Ordering> {
                ::core::option::Option::Some(::core::cmp::Ord::cmp(self, other))
            }
        }
    };
    TokenStream::from(expanded)
}

/// Chain a list of per-field `Ordering` expressions lexicographically.
fn chain_cmps(cmps: &[proc_macro2::TokenStream]) -> proc_macro2::TokenStream {
    let mut iter = cmps.iter();
    match iter.next() {
        None => quote! { ::core::cmp::Ordering::Equal },
        Some(first) => {
            let mut acc = quote! { #first };
            for c in iter {
                acc = quote! { #acc.then_with(|| #c) };
            }
            acc
        }
    }
}

/// Per-field `eq` tests and `cmp` orderings for a struct's fields, addressed via
/// `self.<field>` / `other.<field>`.
fn struct_field_cmps(
    fields: &Fields,
    eq_one: &dyn Fn(&proc_macro2::TokenStream, &proc_macro2::TokenStream, bool) -> proc_macro2::TokenStream,
    cmp_one: &dyn Fn(&proc_macro2::TokenStream, &proc_macro2::TokenStream, bool) -> proc_macro2::TokenStream,
) -> (Vec<proc_macro2::TokenStream>, Vec<proc_macro2::TokenStream>) {
    match fields {
        Fields::Unit => (vec![quote! { true }], vec![]),
        Fields::Named(named) => {
            let mut eqs = Vec::new();
            let mut cmps = Vec::new();
            for f in &named.named {
                let n = f.ident.as_ref().unwrap();
                let l = quote! { &self.#n };
                let r = quote! { &other.#n };
                eqs.push(eq_one(&l, &r, is_arc(&f.ty)));
                cmps.push(cmp_one(&l, &r, is_arc(&f.ty)));
            }
            if eqs.is_empty() { eqs.push(quote! { true }); }
            (eqs, cmps)
        }
        Fields::Unnamed(unnamed) => {
            let mut eqs = Vec::new();
            let mut cmps = Vec::new();
            for (i, f) in unnamed.unnamed.iter().enumerate() {
                let idx = Index::from(i);
                let l = quote! { &self.#idx };
                let r = quote! { &other.#idx };
                eqs.push(eq_one(&l, &r, is_arc(&f.ty)));
                cmps.push(cmp_one(&l, &r, is_arc(&f.ty)));
            }
            if eqs.is_empty() { eqs.push(quote! { true }); }
            (eqs, cmps)
        }
    }
}

#[proc_macro_derive(ReferenceEq)]
pub fn derive_reference_eq(input: TokenStream) -> TokenStream {
    let input = parse_macro_input!(input as DeriveInput);
    let name = &input.ident;

    // Add `metamodelica::ReferenceEq` to every type parameter, mirroring how
    // builtin derives bound their own trait.
    let mut generics = input.generics.clone();
    for param in generics.type_params_mut() {
        param
            .bounds
            .push(syn::parse_quote!(metamodelica::ReferenceEq));
    }
    let (impl_generics, ty_generics, where_clause) = generics.split_for_impl();

    let body = match &input.data {
        Data::Struct(data) => {
            let cmp = fields_cmp(&data.fields, quote!(self), quote!(other));
            quote! { #cmp }
        }
        Data::Enum(data) => {
            let arms = data.variants.iter().map(|v| {
                let vname = &v.ident;
                match &v.fields {
                    Fields::Unit => quote! {
                        (Self::#vname, Self::#vname) => true,
                    },
                    Fields::Named(named) => {
                        let names: Vec<_> = named
                            .named
                            .iter()
                            .map(|f| f.ident.as_ref().unwrap())
                            .collect();
                        let lhs: Vec<_> = names
                            .iter()
                            .map(|n| quote::format_ident!("__refeq_l_{}", n))
                            .collect();
                        let rhs: Vec<_> = names
                            .iter()
                            .map(|n| quote::format_ident!("__refeq_r_{}", n))
                            .collect();
                        quote! {
                            (Self::#vname { #(#names: #lhs),* }, Self::#vname { #(#names: #rhs),* }) =>
                                true #(&& metamodelica::ReferenceEq::reference_eq(#lhs, #rhs))*,
                        }
                    }
                    Fields::Unnamed(unnamed) => {
                        let lhs: Vec<_> = (0..unnamed.unnamed.len())
                            .map(|i| quote::format_ident!("__refeq_l{}", i))
                            .collect();
                        let rhs: Vec<_> = (0..unnamed.unnamed.len())
                            .map(|i| quote::format_ident!("__refeq_r{}", i))
                            .collect();
                        quote! {
                            (Self::#vname(#(#lhs),*), Self::#vname(#(#rhs),*)) =>
                                true #(&& metamodelica::ReferenceEq::reference_eq(#lhs, #rhs))*,
                        }
                    }
                }
            });
            // The catch-all arm is unreachable for single-variant enums, but
            // emitting it unconditionally keeps the expansion simple; allow
            // the lint instead of special-casing.
            quote! {
                #[allow(unreachable_patterns)]
                match (self, other) {
                    #(#arms)*
                    _ => false,
                }
            }
        }
        Data::Union(_) => {
            return syn::Error::new_spanned(name, "ReferenceEq cannot be derived for unions")
                .to_compile_error()
                .into();
        }
    };

    let expanded = quote! {
        impl #impl_generics metamodelica::ReferenceEq for #name #ty_generics #where_clause {
            fn reference_eq(&self, other: &Self) -> bool {
                #body
            }
        }
    };
    TokenStream::from(expanded)
}

/// Conjunction of `ReferenceEq::reference_eq` over all fields of a struct.
fn fields_cmp(
    fields: &Fields,
    lhs: proc_macro2::TokenStream,
    rhs: proc_macro2::TokenStream,
) -> proc_macro2::TokenStream {
    match fields {
        Fields::Unit => quote! { true },
        Fields::Named(named) => {
            let cmps = named.named.iter().map(|f| {
                let n = f.ident.as_ref().unwrap();
                quote! { metamodelica::ReferenceEq::reference_eq(&#lhs.#n, &#rhs.#n) }
            });
            quote! { true #(&& #cmps)* }
        }
        Fields::Unnamed(unnamed) => {
            let cmps = (0..unnamed.unnamed.len()).map(|i| {
                let idx = Index::from(i);
                quote! { metamodelica::ReferenceEq::reference_eq(&#lhs.#idx, &#rhs.#idx) }
            });
            quote! { true #(&& #cmps)* }
        }
    }
}
